import{_ as t,c as r,o as n,ag as s}from"./chunks/framework.GdcW6lnn.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"basics_api/authentication-methods.md","filePath":"basics_api/authentication-methods.md"}'),i={name:"basics_api/authentication-methods.md"};function l(e,o,a,g,p,c){return n(),r("div",null,o[0]||(o[0]=[s('<h2 id="а-методи-аутентифікаціі-детальні-пояснення" tabindex="-1">А) Методи аутентифікації: Детальні пояснення <a class="header-anchor" href="#а-методи-аутентифікаціі-детальні-пояснення" aria-label="Permalink to “А) Методи аутентифікації: Детальні пояснення”">​</a></h2><p>Аутентифікація - це процес підтвердження особи або програми, яка намагається отримати доступ до ресурсу (наприклад, API). Це як перевірка документів перед тим, як пустити когось у будівлю. Існує кілька поширених методів аутентифікації в API:</p><h3 id="🔑-→-api-keys-ключі-api" tabindex="-1">🔑 → API Keys (Ключі API) <a class="header-anchor" href="#🔑-→-api-keys-ключі-api" aria-label="Permalink to “🔑 → API Keys (Ключі API)”">​</a></h3><p><strong>Що це?</strong></p><p>API Key (ключ API) - це простий секретний токен (рядок символів), який клієнт (наприклад, ваша програма) передає серверу для ідентифікації. Це схоже на <strong>персональний пароль</strong> для вашої програми, який дозволяє їй користуватися API.</p><p><strong>Як це працює?</strong></p><ol><li><strong>Отримання ключа:</strong> Розробник програми реєструє свою програму на платформі, що надає API, і отримує унікальний API Key.</li><li><strong>Передача ключа:</strong> Кожен запит до API від програми включає цей ключ. Зазвичай ключ передається в одному з: <ul><li><strong>Заголовку HTTP:</strong> Наприклад, у заголовку <code>X-API-Key: YOUR_API_KEY</code>.</li><li><strong>Параметрі запиту (Query Parameter):</strong> Наприклад, у URL на кшталт <code>https://api.example.com/data?api_key=YOUR_API_KEY</code>.</li></ul></li><li><strong>Перевірка ключа:</strong> Сервер API отримує ключ і перевіряє, чи він є дійсним та чи має програма право на доступ до запитуваного ресурсу.</li><li><strong>Доступ надано/відмовлено:</strong> Якщо ключ дійсний, сервер обробляє запит і повертає дані. Інакше - повертає помилку (зазвичай <code>401 Unauthorized</code>).</li></ol><p><strong>Переваги:</strong></p><ul><li><strong>Простота:</strong> Легко реалізувати як на стороні клієнта, так і на стороні сервера.</li><li><strong>Швидкість:</strong> Перевірка ключа зазвичай відбувається швидко.</li></ul><p><strong>Недоліки:</strong></p><ul><li><strong>Безпека:</strong> Ключі API є статичними та можуть бути вкрадені, якщо їх не захищати належним чином (наприклад, не зберігати в коді відкрито).</li><li><strong>Обмежені можливості:</strong> Зазвичай не надають детальної інформації про користувача, лише про програму.</li><li><strong>Складність відкликання:</strong> Відкликати скомпрометований ключ може бути складно (потрібно генерувати новий та оновлювати всі програми, що його використовують).</li></ul><p><strong>Використання:</strong></p><p>Часто використовуються для публічних API, API для IoT-пристроїв або для простої ідентифікації програм.</p><hr><h3 id="🛡️-→-oauth-2-open-authorization-2-0" tabindex="-1">🛡️ → OAuth 2 (Open Authorization 2.0) <a class="header-anchor" href="#🛡️-→-oauth-2-open-authorization-2-0" aria-label="Permalink to “🛡️ → OAuth 2 (Open Authorization 2.0)”">​</a></h3><p><strong>Що це?</strong></p><p>OAuth 2 - це <strong>стандарт авторизації</strong>, який дозволяє стороннім програмам отримувати обмежений доступ до ресурсів користувача на іншому сервісі <strong>без розкриття облікових даних користувача</strong> (наприклад, логіна та пароля). Уявіть собі, як ви дозволяєте програмі редагувати ваші фотографії у хмарному сховищі, не надаючи їй свій пароль до цього сховища.</p><p><strong>Основні учасники:</strong></p><ul><li><strong>Resource Owner (Власник ресурсу):</strong> Користувач, чиї дані потрібно отримати (наприклад, ви).</li><li><strong>Client (Клієнт):</strong> Стороння програма, яка хоче отримати доступ до ресурсів користувача (наприклад, програма для редагування фотографій).</li><li><strong>Authorization Server (Сервер авторизації):</strong> Сервер, який видає токени доступу після успішної аутентифікації користувача та отримання його згоди.</li><li><strong>Resource Server (Сервер ресурсів):</strong> Сервер, який зберігає ресурси користувача і перевіряє токени доступу перед наданням доступу.</li></ul><p><strong>Основні потоки (Grant Types):</strong></p><p>OAuth 2 визначає кілька способів отримання токенів доступу (&quot;grant types&quot;), залежно від типу клієнта та сценарію використання. Найпоширеніші:</p><ul><li><strong>Authorization Code Grant:</strong> Використовується для веб-додатків. Включає перенаправлення користувача на сервер авторизації для надання згоди, а потім обмін коду авторизації на токен доступу.</li><li><strong>Implicit Grant:</strong> (Зазвичай не рекомендується через безпекові міркування) Використовується для односторінкових додатків (SPA). Токен доступу повертається безпосередньо через URL-фрагмент після надання згоди.</li><li><strong>Password Grant:</strong> Клієнт безпосередньо передає облікові дані користувача на сервер авторизації. Використовується рідко і лише для довірених клієнтів.</li><li><strong>Client Credentials Grant:</strong> Використовується для авторизації між серверами, коли клієнт діє від свого імені, а не від імені користувача.</li></ul><p><strong>Як це працює (спрощено для Authorization Code Grant):</strong></p><ol><li>Клієнт перенаправляє користувача на сервер авторизації.</li><li>Користувач вводить свої облікові дані та надає згоду клієнту на доступ до своїх ресурсів.</li><li>Сервер авторизації перенаправляє користувача назад до клієнта з кодом авторизації.</li><li>Клієнт відправляє код авторизації на сервер авторизації та отримує токен доступу (та, можливо, токен оновлення).</li><li>Клієнт використовує токен доступу для запитів до сервера ресурсів.</li><li>Сервер ресурсів перевіряє токен доступу та надає доступ до ресурсів користувача.</li></ol><p><strong>Переваги:</strong></p><ul><li><strong>Безпека:</strong> Користувачі не розкривають свої облікові дані стороннім програмам.</li><li><strong>Обмежений доступ:</strong> Користувач може надати клієнту лише певні права доступу (наприклад, лише читання профілю, а не редагування).</li><li><strong>Відкликання доступу:</strong> Користувач може в будь-який момент відкликати доступ, наданий клієнту.</li></ul><p><strong>Недоліки:</strong></p><ul><li><strong>Складність:</strong> Реалізація може бути складнішою порівняно з API Keys.</li><li><strong>Більше запитів:</strong> Потрібно кілька кроків для отримання токена доступу.</li></ul><p><strong>Використання:</strong></p><p>Стандарт для авторизації в багатьох сучасних веб-додатках та API (наприклад, &quot;Увійти через Google&quot;, &quot;Підключити до Facebook&quot;).</p><hr><h3 id="🗝️-→-jwt-json-web-tokens" tabindex="-1">🗝️ → JWT (JSON Web Tokens) <a class="header-anchor" href="#🗝️-→-jwt-json-web-tokens" aria-label="Permalink to “🗝️ → JWT (JSON Web Tokens)”">​</a></h3><p><strong>Що це?</strong></p><p>JWT (JSON Web Token) - це <strong>компактний, самодостатній спосіб безпечної передачі інформації між сторонами</strong> як об&#39;єкт JSON, підписаний цифровим підписом. Це схоже на <strong>електронний квиток</strong> 🎫, який містить інформацію про користувача та підтвердження його автентичності.</p><p><strong>Структура JWT:</strong></p><p>JWT складається з трьох частин, розділених крапками (<code>.</code>):</p><ol><li><strong>Header (Заголовок):</strong> Містить інформацію про тип токена (зазвичай &quot;JWT&quot;) та алгоритм підпису (наприклад, HMAC SHA256 або RSA).</li><li><strong>Payload (Корисне навантаження):</strong> Містить &quot;твердження&quot; (claims) - інформацію про користувача та інші дані. Існують зареєстровані твердження (наприклад, <code>iss</code> - issuer, <code>sub</code> - subject, <code>exp</code> - expiration time), публічні твердження (які можуть бути визначені сторонами) та приватні твердження (специфічні для програми).</li><li><strong>Signature (Підпис):</strong> Створюється шляхом шифрування закодованих заголовка та корисного навантаження з використанням секретного ключа (для HMAC) або приватного ключа (для RSA) та алгоритму, вказаного в заголовку. Підпис використовується для перевірки цілісності токена та підтвердження того, що він не був підроблений.</li></ol><p><strong>Як це працює (спрощено):</strong></p><ol><li>Коли користувач успішно аутентифікується на сервері, сервер генерує JWT, що містить інформацію про користувача (наприклад, його ID) та підписує його.</li><li>Сервер повертає JWT клієнту (зазвичай у заголовку <code>Authorization: Bearer YOUR_JWT</code>).</li><li>Клієнт зберігає JWT (наприклад, у localStorage або cookie) та включає його в кожен наступний запит до захищених ресурсів API (зазвичай у заголовку <code>Authorization: Bearer YOUR_JWT</code>).</li><li>Сервер API отримує JWT, перевіряє його підпис за допомогою секретного (або публічного) ключа та перевіряє твердження (наприклад, чи не закінчився термін дії токена).</li><li>Якщо підпис дійсний і твердження валідні, сервер вважає користувача автентифікованим та надає доступ до ресурсу.</li></ol><p><strong>Переваги:</strong></p><ul><li><strong>Самодостатність:</strong> Вся необхідна інформація про користувача міститься в самому токені.</li><li><strong>Безпека:</strong> Підпис гарантує цілісність та автентичність токена.</li><li><strong>Масштабованість:</strong> Серверу не потрібно зберігати сесійну інформацію (stateless), що полегшує масштабування.</li><li><strong>Простота використання:</strong> Легко передавати через HTTP-заголовки.</li></ul><p><strong>Недоліки:</strong></p><ul><li><strong>Розмір:</strong> Може бути більшим за прості сесійні ідентифікатори.</li><li><strong>Відкликання:</strong> Відкликати JWT може бути складніше, оскільки вони самодостатні. Зазвичай використовують короткий термін дії або додаткові механізми відкликання.</li></ul><p><strong>Використання:</strong></p><p>Широко використовується для аутентифікації та авторизації в сучасних веб-додатках, мобільних додатках та мікросервісних архітектурах.</p><hr><h3 id="👤-→-basic-auth-базова-аутентифікація" tabindex="-1">👤 → Basic Auth (Базова аутентифікація) <a class="header-anchor" href="#👤-→-basic-auth-базова-аутентифікація" aria-label="Permalink to “👤 → Basic Auth (Базова аутентифікація)”">​</a></h3><p><strong>Що це?</strong></p><p>Basic Auth (базова аутентифікація) - це <strong>простий метод аутентифікації</strong>, в якому клієнт передає свої облікові дані (ім&#39;я користувача та пароль) у кожному запиті до API через <strong>заголовок <code>Authorization</code></strong>. Пароль кодується в форматі Base64.</p><p><strong>Як це працює:</strong></p><ol><li>Клієнт отримує ім&#39;я користувача та пароль.</li><li>Клієнт об&#39;єднує ім&#39;я користувача та пароль у форматі <code>username:password</code>.</li><li>Клієнт кодує цей рядок у Base64.</li><li>Клієнт додає заголовок <code>Authorization</code> до HTTP-запиту зі значенням <code>Basic BASE64_ENCODED_CREDENTIALS</code>.</li><li>Сервер API отримує запит, декодує значення заголовка <code>Authorization</code> з Base64, отримує ім&#39;я користувача та пароль і перевіряє їх.</li><li>Якщо облікові дані дійсні, сервер обробляє запит. Інакше - повертає помилку <code>401 Unauthorized</code>.</li></ol><p><strong>Приклад заголовка:</strong></p>',52)]))}const h=t(i,[["render",l]]);export{u as __pageData,h as default};
